  1→/**
  2→ * Centralized storage service
  3→ * Replaces direct localStorage and chrome.storage calls
  4→ * Implements Repository pattern with type safety
  5→ */
  6→import { ErrorCode, StorageError } from '../errors/AppError';
  7→import type { Result, StorageKey } from '../types/common';
  8→import {
  9→  hasValidExtensionContext,
 10→  isExtensionContextInvalidatedError,
 11→} from '../utils/extensionContext';
 12→import { logger } from './LoggerService';
 13→
 14→export interface IStorageService {
 15→  get<T>(key: StorageKey): Promise<Result<T>>;
 16→  set<T>(key: StorageKey, value: T): Promise<Result<void>>;
 17→  remove(key: StorageKey): Promise<Result<void>>;
 18→  clear(): Promise<Result<void>>;
 19→}
 20→
 21→/**
 22→ * Base Chrome Storage implementation (DRY: shared logic)
 23→ */
 24→abstract class BaseChromeStorageService implements IStorageService {
 25→  protected abstract readonly storageArea: chrome.storage.StorageArea;
 26→  protected abstract readonly loggerName: string;
 27→
 28→  protected get logger(): ReturnType<typeof logger.createChild> {
 29→    // Lazy getter to avoid abstract property access in constructor
 30→    return logger.createChild(this.loggerName);
 31→  }
 32→
 33→  private isContextInvalidated(error: unknown): boolean {
 34→    return isExtensionContextInvalidatedError(error) || !hasValidExtensionContext();
 35→  }
 36→
 37→  async get<T>(key: StorageKey): Promise<Result<T>> {
 38→    try {
 39→      this.logger.debug(`Reading key: ${key}`);
 40→
 41→      const result = await new Promise<Record<string, T>>((resolve, reject) => {
 42→        this.storageArea.get([key], (items) => {
 43→          if (chrome.runtime.lastError) {
 44→            reject(new Error(chrome.runtime.lastError.message));
 45→            return;
 46→          }
 47→          resolve(items as Record<string, T>);
 48→        });
 49→      });
 50→
 51→      const value = result[key];
 52→
 53→      if (value === undefined) {
 54→        this.logger.debug(`Key not found: ${key}`);
 55→        return {
 56→          success: false,
 57→          error: new StorageError(ErrorCode.STORAGE_READ_FAILED, `Key not found: ${key}`, { key }),
 58→        };
 59→      }
 60→
 61→      this.logger.debug(`Successfully read key: ${key}`);
 62→      return { success: true, data: value };
 63→    } catch (error) {
 64→      if (this.isContextInvalidated(error)) {
 65→        this.logger.debug(`Extension context invalidated while reading key: ${key}`);
 66→        return {
 67→          success: false,
 68→          error: new StorageError(
 69→            ErrorCode.STORAGE_READ_FAILED,
 70→            `Extension context invalidated while reading key: ${key}`,
 71→            { key },
 72→            error instanceof Error ? error : undefined,
 73→          ),
 74→        };
 75→      }
 76→      this.logger.error(`Failed to read key: ${key}`, { error });
 77→      return {
 78→        success: false,
 79→        error: new StorageError(
 80→          ErrorCode.STORAGE_READ_FAILED,
 81→          `Failed to read key: ${key}`,
 82→          { key },
 83→          error instanceof Error ? error : undefined,
 84→        ),
 85→      };
 86→    }
 87→  }
 88→
 89→  async set<T>(key: StorageKey, value: T): Promise<Result<void>> {
 90→    try {
 91→      this.logger.debug(`Writing key: ${key}`);
 92→
 93→      await new Promise<void>((resolve, reject) => {
 94→        this.storageArea.set({ [key]: value }, () => {
 95→          if (chrome.runtime.lastError) {
 96→            reject(new Error(chrome.runtime.lastError.message));
 97→          } else {
 98→            resolve();
 99→          }
100→        });
101→      });
102→
103→      this.logger.debug(`Successfully wrote key: ${key}`);
104→      return { success: true, data: undefined };
105→    } catch (error) {
106→      if (this.isContextInvalidated(error)) {
107→        this.logger.debug(`Extension context invalidated while writing key: ${key}`);
108→        return {
109→          success: false,
110→          error: new StorageError(
111→            ErrorCode.STORAGE_WRITE_FAILED,
112→            `Extension context invalidated while writing key: ${key}`,
113→            { key, value },
114→            error instanceof Error ? error : undefined,
115→          ),
116→        };
117→      }
118→      this.logger.error(`Failed to write key: ${key}`, { error });
119→      return {
120→        success: false,
121→        error: new StorageError(
122→          ErrorCode.STORAGE_WRITE_FAILED,
123→          `Failed to write key: ${key}`,
124→          { key, value },
125→          error instanceof Error ? error : undefined,
126→        ),
127→      };
128→    }
129→  }
130→
131→  async remove(key: StorageKey): Promise<Result<void>> {
132→    try {
133→      this.logger.debug(`Removing key: ${key}`);
134→
135→      await new Promise<void>((resolve, reject) => {
136→        this.storageArea.remove(key, () => {
137→          if (chrome.runtime.lastError) {
138→            reject(new Error(chrome.runtime.lastError.message));
139→          } else {
140→            resolve();
141→          }
142→        });
143→      });
144→
145→      this.logger.debug(`Successfully removed key: ${key}`);
146→      return { success: true, data: undefined };
147→    } catch (error) {
148→      if (this.isContextInvalidated(error)) {
149→        this.logger.debug(`Extension context invalidated while removing key: ${key}`);
150→        return {
151→          success: false,
152→          error: new StorageError(
153→            ErrorCode.STORAGE_WRITE_FAILED,
154→            `Extension context invalidated while removing key: ${key}`,
155→            { key },
156→            error instanceof Error ? error : undefined,
157→          ),
158→        };
159→      }
160→      this.logger.error(`Failed to remove key: ${key}`, { error });
161→      return {
162→        success: false,
163→        error: new StorageError(
164→          ErrorCode.STORAGE_WRITE_FAILED,
165→          `Failed to remove key: ${key}`,
166→          { key },
167→          error instanceof Error ? error : undefined,
168→        ),
169→      };
170→    }
171→  }
172→
173→  async clear(): Promise<Result<void>> {
174→    try {
175→      this.logger.debug('Clearing all storage');
176→
177→      await new Promise<void>((resolve, reject) => {
178→        this.storageArea.clear(() => {
179→          if (chrome.runtime.lastError) {
180→            reject(new Error(chrome.runtime.lastError.message));
181→          } else {
182→            resolve();
183→          }
184→        });
185→      });
186→
187→      this.logger.debug('Successfully cleared storage');
188→      return { success: true, data: undefined };
189→    } catch (error) {
190→      if (this.isContextInvalidated(error)) {
191→        this.logger.debug('Extension context invalidated while clearing storage');
192→        return {
193→          success: false,
194→          error: new StorageError(
195→            ErrorCode.STORAGE_WRITE_FAILED,
196→            'Extension context invalidated while clearing storage',
197→            {},
198→            error instanceof Error ? error : undefined,
199→          ),
200→        };
201→      }
202→      this.logger.error('Failed to clear storage', { error });
203→      return {
204→        success: false,
205→        error: new StorageError(
206→          ErrorCode.STORAGE_WRITE_FAILED,
207→          'Failed to clear storage',
208→          {},
209→          error instanceof Error ? error : undefined,
210→        ),
211→      };
212→    }
213→  }
214→}
