216→/**
217→ * Chrome Storage Sync implementation (100KB quota, cross-device sync)
218→ * Use for small settings and preferences
219→ */
220→export class ChromeStorageService extends BaseChromeStorageService {
221→  protected readonly storageArea = chrome.storage.sync;
222→  protected readonly loggerName = 'ChromeStorage';
223→}
