225→/**
226→ * Chrome Storage Local implementation (5-10MB quota, local only)
227→ * Use for large data like prompts
228→ */
229→export class ChromeLocalStorageService extends BaseChromeStorageService {
230→  protected readonly storageArea = chrome.storage.local;
231→  protected readonly loggerName = 'ChromeLocalStorage';
232→}
233→
234→/**
235→ * LocalStorage implementation (fallback)
236→ */
237→export class LocalStorageService implements IStorageService {
238→  private readonly logger = logger.createChild('LocalStorage');
239→
240→  async get<T>(key: StorageKey): Promise<Result<T>> {
241→    try {
242→      this.logger.debug(`Reading key: ${key}`);
243→
244→      const raw = localStorage.getItem(key);
245→
246→      if (raw === null) {
247→        this.logger.debug(`Key not found: ${key}`);
248→        return {
249→          success: false,
250→          error: new StorageError(ErrorCode.STORAGE_READ_FAILED, `Key not found: ${key}`, { key }),
251→        };
252→      }
253→
254→      const value = JSON.parse(raw) as T;
255→
256→      this.logger.debug(`Successfully read key: ${key}`);
257→      return { success: true, data: value };
258→    } catch (error) {
259→      this.logger.error(`Failed to read/parse key: ${key}`, { error });
260→      return {
261→        success: false,
262→        error: new StorageError(
263→          ErrorCode.STORAGE_PARSE_FAILED,
264→          `Failed to read/parse key: ${key}`,
265→          { key },
266→          error instanceof Error ? error : undefined,
267→        ),
268→      };
269→    }
270→  }
271→
272→  async set<T>(key: StorageKey, value: T): Promise<Result<void>> {
273→    try {
274→      this.logger.debug(`Writing key: ${key}`);
275→
276→      const raw = JSON.stringify(value);
277→      localStorage.setItem(key, raw);
278→
279→      this.logger.debug(`Successfully wrote key: ${key}`);
280→      return { success: true, data: undefined };
281→    } catch (error) {
282→      this.logger.error(`Failed to write key: ${key}`, { error });
283→      return {
284→        success: false,
285→        error: new StorageError(
286→          ErrorCode.STORAGE_WRITE_FAILED,
287→          `Failed to write key: ${key}`,
288→          { key, value },
289→          error instanceof Error ? error : undefined,
290→        ),
291→      };
292→    }
293→  }
294→
295→  async remove(key: StorageKey): Promise<Result<void>> {
296→    try {
297→      this.logger.debug(`Removing key: ${key}`);
298→
299→      localStorage.removeItem(key);
300→
301→      this.logger.debug(`Successfully removed key: ${key}`);
302→      return { success: true, data: undefined };
303→    } catch (error) {
304→      this.logger.error(`Failed to remove key: ${key}`, { error });
305→      return {
306→        success: false,
307→        error: new StorageError(
308→          ErrorCode.STORAGE_WRITE_FAILED,
309→          `Failed to remove key: ${key}`,
310→          { key },
311→          error instanceof Error ? error : undefined,
312→        ),
313→      };
314→    }
315→  }
316→
317→  async clear(): Promise<Result<void>> {
318→    try {
319→      this.logger.debug('Clearing all storage');
320→
321→      localStorage.clear();
322→
323→      this.logger.debug('Successfully cleared storage');
324→      return { success: true, data: undefined };
325→    } catch (error) {
326→      this.logger.error('Failed to clear storage', { error });
327→      return {
328→        success: false,
329→        error: new StorageError(
330→          ErrorCode.STORAGE_WRITE_FAILED,
331→          'Failed to clear storage',
332→          {},
333→          error instanceof Error ? error : undefined,
334→        ),
335→      };
336→    }
337→  }
338→}
