340→/**
341→ * Storage type selection
342→ */
343→export type StorageType = 'sync' | 'local';
344→
345→/**
346→ * Storage factory - automatically selects the best available storage
347→ */
348→export class StorageFactory {
349→  /**
350→   * Create a storage service instance
351→   * @param type - 'sync' for chrome.storage.sync (100KB, cross-device), 'local' for chrome.storage.local (5-10MB, local only)
352→   */
353→  static create(type: StorageType = 'sync'): IStorageService {
354→    if (typeof chrome !== 'undefined' && chrome.storage) {
355→      if (type === 'local' && chrome.storage.local) {
356→        logger.info('Using ChromeLocalStorageService');
357→        return new ChromeLocalStorageService();
358→      }
359→
360→      if (chrome.storage.sync) {
361→        logger.info('Using ChromeStorageService');
362→        return new ChromeStorageService();
363→      }
364→    }
365→
366→    logger.info('Using LocalStorageService (fallback)');
367→    return new LocalStorageService();
368→  }
369→}
370→
371→// Export singleton instances
372→export const storageService = StorageFactory.create('sync'); // For folders (small data, cross-device sync)
373→export const promptStorageService = StorageFactory.create('local'); // For prompts (large data, local only)
