 54→/**
 55→ * Staggered initialization to prevent "thundering herd" problem when multiple tabs
 56→ * are restored simultaneously (e.g., after browser restart).
 57→ *
 58→ * Background tabs get a random delay (3-8s) to distribute initialization load.
 59→ * Foreground tabs initialize immediately for good UX.
 60→ *
 61→ * This prevents triggering Google's rate limiting when restoring sessions with
 62→ * many Gemini tabs containing long conversations.
 63→ */
 64→
 65→// Initialization delay constants (in milliseconds)
 66→const HEAVY_FEATURE_INIT_DELAY = 100; // For resource-intensive features (Timeline, Folder)
 67→const LIGHT_FEATURE_INIT_DELAY = 50; // For lightweight features
 68→const BACKGROUND_TAB_MIN_DELAY = 3000; // Minimum delay for background tabs
 69→const BACKGROUND_TAB_MAX_DELAY = 8000; // Maximum delay for background tabs (3000 + 5000)
 70→
 71→let initialized = false;
 72→let initializationTimer: number | null = null;
 73→let folderManagerInstance: Awaited<ReturnType<typeof startFolderManager>> | null = null;
 74→
 75→let promptManagerInstance: Awaited<ReturnType<typeof startPromptManager>> | null = null;
 76→let quoteReplyCleanup: (() => void) | null = null;
 77→let responseFinishReminderCleanup: (() => void) | null = null;
 78→let sendBehaviorCleanup: (() => void) | null = null;
 79→let forkCleanup: (() => void) | null = null;
