 81→async function isForkFeatureEnabled(): Promise<boolean> {
 82→  try {
 83→    const result = await chrome.storage?.sync?.get({ [StorageKeys.FORK_ENABLED]: false });
 84→    return isForkFeatureEnabledValue(result?.[StorageKeys.FORK_ENABLED]);
 85→  } catch {
 86→    return false;
 87→  }
 88→}
