 90→/**
 91→ * Check if current hostname matches any custom websites
 92→ */
 93→async function isCustomWebsite(): Promise<boolean> {
 94→  try {
 95→    const result = await chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] });
 96→    const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
 97→      ? result.gvPromptCustomWebsites
 98→      : [];
 99→
100→    // Normalize current hostname
101→    const currentHost = location.hostname.toLowerCase().replace(/^www\./, '');
102→
103→    console.log('[Gemini Voyager] Checking custom websites:', {
104→      currentHost,
105→      customWebsites,
106→      hostname: location.hostname,
107→    });
108→
109→    const isCustom = customWebsites.some((website: string) => {
110→      const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
111→      const matches =
112→        currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
113→      console.log('[Gemini Voyager] Comparing:', { currentHost, normalizedWebsite, matches });
114→      return matches;
115→    });
116→
117→    console.log('[Gemini Voyager] Is custom website:', isCustom);
118→    return isCustom;
119→  } catch (e) {
120→    if (isExtensionContextInvalidatedError(e)) {
121→      return false;
122→    }
123→    console.error('[Gemini Voyager] Error checking custom websites:', e);
124→    return false;
125→  }
126→}
