128→/**
129→ * Initialize all features sequentially to reduce simultaneous load
130→ */
131→async function initializeFeatures(): Promise<void> {
132→  if (initialized) return;
133→  initialized = true;
134→
135→  try {
136→    if (!hasValidExtensionContext()) {
137→      return;
138→    }
139→    // Sequential initialization with small delays between features
140→    // to further reduce simultaneous resource usage
141→    const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
142→
143→    // Check if this is a custom website (only prompt manager should be enabled)
144→    const isCustomSite = await isCustomWebsite();
145→
146→    if (isCustomSite) {
147→      // Only start prompt manager for custom websites
148→      console.log('[Gemini Voyager] Custom website detected, starting Prompt Manager only');
149→
150→      promptManagerInstance = await startPromptManager();
151→      return;
152→    }
153→
154→    console.log('[Gemini Voyager] Not a custom website, checking for Gemini/AI Studio');
155→
156→    const isEnterprise = isGeminiEnterpriseEnvironment(
157→      {
158→        hostname: location.hostname,
159→        pathname: location.pathname,
160→        search: location.search,
161→        hash: location.hash,
162→      },
163→      document,
164→    );
165→
166→    if (isEnterprise) {
167→      console.log('[Gemini Voyager] Gemini Enterprise detected, starting Prompt Manager only');
168→      promptManagerInstance = await startPromptManager();
169→      return;
170→    }
171→
172→    if (location.hostname === 'gemini.google.com') {
173→      // Timeline is most resource-intensive, start it first
174→      startTimeline();
175→      await delay(HEAVY_FEATURE_INIT_DELAY);
176→
177→      folderManagerInstance = await startFolderManager();
178→      await delay(HEAVY_FEATURE_INIT_DELAY);
179→
180→      startFolderSpacingAdjuster('gemini');
181→      await delay(LIGHT_FEATURE_INIT_DELAY);
182→
183→      startChatWidthAdjuster();
184→      await delay(LIGHT_FEATURE_INIT_DELAY);
185→
186→      startEditInputWidthAdjuster();
187→      await delay(LIGHT_FEATURE_INIT_DELAY);
188→
189→      startSidebarWidthAdjuster();
190→      await delay(LIGHT_FEATURE_INIT_DELAY);
191→
192→      startSidebarAutoHide();
193→      await delay(LIGHT_FEATURE_INIT_DELAY);
194→
195→      startSnowEffect();
196→      startSakuraEffect();
197→      startRainEffect();
198→      await delay(LIGHT_FEATURE_INIT_DELAY);
199→
200→      startInputCollapse();
201→      await delay(LIGHT_FEATURE_INIT_DELAY);
202→
203→      startPreventAutoScroll();
204→      await delay(LIGHT_FEATURE_INIT_DELAY);
205→
206→      startFormulaCopy();
207→
208→      await delay(LIGHT_FEATURE_INIT_DELAY);
209→
210→      // Quote Reply - conditionally start based on storage setting
211→      const quoteReplyResult = await new Promise<{ gvQuoteReplyEnabled?: boolean }>((resolve) => {
212→        try {
213→          chrome.storage?.sync?.get({ gvQuoteReplyEnabled: true }, resolve);
214→        } catch {
215→          resolve({ gvQuoteReplyEnabled: true });
216→        }
217→      });
218→      if (quoteReplyResult.gvQuoteReplyEnabled !== false) {
219→        quoteReplyCleanup = startQuoteReply();
220→      }
221→      await delay(LIGHT_FEATURE_INIT_DELAY);
222→
223→      // Watermark remover - based on gemini-watermark-remover by journey-ad
224→      // https://github.com/journey-ad/gemini-watermark-remover
225→      // Skip on Safari due to fetch interceptor limitations in extension sandbox
226→      if (!isSafari()) {
227→        startWatermarkRemover();
228→      }
229→      await delay(LIGHT_FEATURE_INIT_DELAY);
230→
231→      startTitleUpdater();
232→      await delay(LIGHT_FEATURE_INIT_DELAY);
233→
234→      responseFinishReminderCleanup = await startResponseFinishReminder();
235→      await delay(LIGHT_FEATURE_INIT_DELAY);
236→
237→      startDeepResearchExport();
238→      await delay(LIGHT_FEATURE_INIT_DELAY);
239→
240→      startContextSync();
241→      await delay(LIGHT_FEATURE_INIT_DELAY);
242→
243→      // Send behavior (Ctrl+Enter to send)
244→      sendBehaviorCleanup = await startSendBehavior();
245→      await delay(LIGHT_FEATURE_INIT_DELAY);
246→
247→      // Recents hider - hide/show toggle for recent items section
248→      startRecentsHider();
249→      await delay(LIGHT_FEATURE_INIT_DELAY);
250→
251→      // Gems hider - hide/show toggle for Gems list section
252→      startGemsHider();
253→      await delay(LIGHT_FEATURE_INIT_DELAY);
254→
255→      // Upsell hider - hide "Upgrade to Google AI Ultra" buttons
256→      void startUpsellHider();
257→      await delay(LIGHT_FEATURE_INIT_DELAY);
258→
259→      // Markdown Patcher - fixes broken bold tags due to HTML injection
260→      startMarkdownPatcher();
261→      await delay(LIGHT_FEATURE_INIT_DELAY);
262→
263→      // Default Model Manager
264→      DefaultModelManager.getInstance().init();
265→      await delay(LIGHT_FEATURE_INIT_DELAY);
266→
267→      startExportButton();
268→      await delay(LIGHT_FEATURE_INIT_DELAY);
269→
270→      if (await isForkFeatureEnabled()) {
271→        forkCleanup = startFork();
272→        await delay(LIGHT_FEATURE_INIT_DELAY);
273→      }
274→
275→      startChangelog();
276→      await delay(LIGHT_FEATURE_INIT_DELAY);
277→    }
278→
279→    if (
280→      location.hostname === 'gemini.google.com' ||
281→      location.hostname === 'aistudio.google.com' ||
282→      location.hostname === 'aistudio.google.cn'
283→    ) {
284→      promptManagerInstance = await startPromptManager();
285→      await delay(HEAVY_FEATURE_INIT_DELAY);
286→    }
287→
288→    if (location.hostname === 'gemini.google.com') {
289→      // Initialize Mermaid rendering (lightweight)
290→      startMermaid();
291→      await delay(LIGHT_FEATURE_INIT_DELAY);
292→    }
293→
294→    if (location.hostname === 'aistudio.google.com' || location.hostname === 'aistudio.google.cn') {
295→      // Check if user has disabled Voyager on AI Studio
296→      const aiStudioEnabled = await new Promise<boolean>((resolve) => {
297→        try {
298→          chrome.storage?.sync?.get({ [StorageKeys.GV_AISTUDIO_ENABLED]: true }, (res) =>
299→            resolve(res?.[StorageKeys.GV_AISTUDIO_ENABLED] !== false),
300→          );
301→        } catch {
302→          resolve(true);
303→        }
304→      });
305→
306→      if (!aiStudioEnabled) {
307→        console.log('[Gemini Voyager] AI Studio features disabled by user');
308→        return;
