320→    }
321→  } catch (e) {
322→    if (isExtensionContextInvalidatedError(e)) {
323→      return;
324→    }
325→    console.error('[Gemini Voyager] Initialization error:', e);
326→  }
327→}
328→
329→/**
330→ * Determine initialization delay based on tab visibility
331→ */
332→function getInitializationDelay(): number {
333→  // Check if tab is currently visible
334→  const isVisible = document.visibilityState === 'visible';
335→
336→  if (isVisible) {
337→    // Foreground tab: initialize immediately for good UX
338→    console.log('[Gemini Voyager] Foreground tab detected, initializing immediately');
339→    return 0;
340→  } else {
341→    // Background tab: add random delay to distribute load across multiple tabs
342→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
343→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
344→    console.log(
345→      `[Gemini Voyager] Background tab detected, delaying initialization by ${Math.round(randomDelay)}ms`,
346→    );
347→    return randomDelay;
348→  }
349→}
350→
351→/**
352→ * Handle tab visibility changes
353→ */
354→function handleVisibilityChange(): void {
355→  if (document.visibilityState === 'visible' && !initialized) {
356→    // Tab became visible before initialization completed
357→    // Cancel any pending delayed initialization and start immediately
358→    if (initializationTimer !== null) {
359→      clearTimeout(initializationTimer);
360→      initializationTimer = null;
361→      console.log('[Gemini Voyager] Tab became visible, initializing immediately');
362→    }
363→    initializeFeatures();
364→  }
365→}
366→
367→// Main initialization logic
368→(function () {
369→  try {
370→    if (!hasValidExtensionContext()) return;
371→
372→    const onUnhandledRejection = (event: PromiseRejectionEvent) => {
373→      if (isExtensionContextInvalidatedError(event.reason)) {
374→        event.preventDefault();
375→      }
376→    };
377→    const onWindowError = (event: ErrorEvent) => {
378→      if (isExtensionContextInvalidatedError(event.error ?? event.message)) {
379→        event.preventDefault();
380→      }
381→    };
382→    window.addEventListener('unhandledrejection', onUnhandledRejection);
383→    window.addEventListener('error', onWindowError);
384→    const onStorageChanged = (
385→      changes: Record<string, chrome.storage.StorageChange>,
386→      areaName: string,
387→    ) => {
388→      if (
389→        (areaName !== 'sync' && areaName !== 'local') ||
390→        location.hostname !== 'gemini.google.com'
391→      ) {
392→        return;
393→      }
394→
395→      const forkSetting = changes[StorageKeys.FORK_ENABLED];
396→      if (!forkSetting) return;
397→
398→      const enabled = isForkFeatureEnabledValue(forkSetting.newValue);
399→      if (enabled) {
400→        if (!forkCleanup) {
401→          forkCleanup = startFork();
402→        }
403→      } else if (forkCleanup) {
404→        forkCleanup();
405→        forkCleanup = null;
406→      }
407→    };
408→
409→    // Quick check: only run on supported websites
410→    const hostname = location.hostname.toLowerCase();
411→    const isSupportedSite =
412→      hostname.includes('gemini.google.com') ||
413→      hostname.includes('business.gemini.google') ||
414→      hostname.includes('aistudio.google.com') ||
415→      hostname.includes('aistudio.google.cn');
416→
417→    // Initialize KaTeX configuration early to suppress Unicode warnings
418→    // This must run before any formulas are rendered on the page
419→    if (isSupportedSite) {
420→      initKaTeXConfig();
421→      // Initialize i18n early to ensure translations are available
422→      initI18n().catch((e) => console.error('[Gemini Voyager] i18n init error:', e));
423→    }
424→
425→    // If not a known site, check if it's a custom website (async)
426→    if (!isSupportedSite) {
427→      // For unknown sites, check storage asynchronously
428→      chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] }, (result) => {
429→        const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
430→          ? result.gvPromptCustomWebsites
431→          : [];
432→        const currentHost = hostname.replace(/^www\./, '');
433→
434→        const isCustomSite = customWebsites.some((website: string) => {
435→          const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
436→          return currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
437→        });
438→
439→        if (isCustomSite) {
440→          console.log('[Gemini Voyager] Custom website detected:', hostname);
441→          initializeFeatures();
442→        } else {
443→          // Not a supported site, exit early
444→          console.log('[Gemini Voyager] Not a supported website, skipping initialization');
445→        }
446→      });
447→      return;
448→    }
449→    chrome.storage?.onChanged?.addListener(onStorageChanged);
450→
451→    const delay = getInitializationDelay();
452→
453→    if (delay === 0) {
454→      // Immediate initialization for foreground tabs
455→      initializeFeatures();
456→    } else {
457→      // Delayed initialization for background tabs
458→      initializationTimer = window.setTimeout(() => {
459→        initializationTimer = null;
460→        initializeFeatures();
461→      }, delay);
462→    }
463→
464→    // Listen for visibility changes to handle tab switching
465→    document.addEventListener('visibilitychange', handleVisibilityChange);
466→
467→    // Setup cleanup on page unload to prevent memory leaks
468→    window.addEventListener('beforeunload', () => {
469→      try {
470→        window.removeEventListener('unhandledrejection', onUnhandledRejection);
471→        window.removeEventListener('error', onWindowError);
472→        if (folderManagerInstance) {
473→          folderManagerInstance.destroy();
474→          folderManagerInstance = null;
475→        }
476→        if (promptManagerInstance) {
477→          promptManagerInstance.destroy();
478→          promptManagerInstance = null;
479→        }
480→        if (quoteReplyCleanup) {
481→          quoteReplyCleanup();
482→          quoteReplyCleanup = null;
483→        }
484→        if (responseFinishReminderCleanup) {
485→          responseFinishReminderCleanup();
486→          responseFinishReminderCleanup = null;
487→        }
488→        if (sendBehaviorCleanup) {
489→          sendBehaviorCleanup();
490→          sendBehaviorCleanup = null;
491→        }
492→        if (forkCleanup) {
493→          forkCleanup();
494→          forkCleanup = null;
495→        }
496→        chrome.storage?.onChanged?.removeListener(onStorageChanged);
497→      } catch (e) {
498→        if (isExtensionContextInvalidatedError(e)) {
499→          return;
500→        }
501→        console.error('[Gemini Voyager] Cleanup error:', e);
502→      }
503→    });
504→  } catch (e) {
505→    if (isExtensionContextInvalidatedError(e)) {
506→      return;
507→    }
508→    console.error('[Gemini Voyager] Fatal initialization error:', e);
509→  }
510→})();
