123→
124→    /* Fallback for browsers without :has() support */
125→    @supports not selector(:has(*)) {
126→      .content-wrapper,
127→      .main-content,
128→      .content-container {
129→        max-width: none !important;
130→      }
131→
132→      main > div:not(:has(button)):not(.main-menu-button) {
133→        max-width: none !important;
