225→function removeStyles() {
226→  const style = document.getElementById(STYLE_ID);
227→  if (style) {
228→    style.remove();
229→  }
230→}
231→
232→const ENABLED_KEY = 'gvChatWidthEnabled';
233→
234→export function startChatWidthAdjuster() {
235→  let currentWidthPercent = DEFAULT_PERCENT;
236→  let enabled = false;
237→
238→  // Load initial state
239→  chrome.storage?.sync?.get({ geminiChatWidth: DEFAULT_PERCENT, [ENABLED_KEY]: false }, (res) => {
240→    const storedWidth = res?.geminiChatWidth;
241→    const numericStoredWidth = typeof storedWidth === 'number' ? storedWidth : DEFAULT_PERCENT;
242→    const normalized = normalizePercent(numericStoredWidth, DEFAULT_PERCENT);
243→    currentWidthPercent = normalized;
244→    enabled = res?.[ENABLED_KEY] === true;
245→
246→    if (enabled) {
247→      applyWidth(currentWidthPercent);
248→    }
249→
250→    if (typeof storedWidth === 'number' && storedWidth !== normalized) {
251→      try {
252→        chrome.storage?.sync?.set({ geminiChatWidth: normalized });
253→      } catch (e) {
254→        console.warn('[Gemini Voyager] Failed to migrate chat width to %:', e);
255→      }
256→    }
257→  });
258→
259→  // Listen for changes from storage
260→  const storageChangeHandler = (
261→    changes: Record<string, chrome.storage.StorageChange>,
262→    area: string,
263→  ) => {
264→    if (area !== 'sync') return;
265→
266→    if (changes[ENABLED_KEY]) {
267→      enabled = changes[ENABLED_KEY].newValue === true;
268→      if (enabled) {
269→        applyWidth(currentWidthPercent);
270→      } else {
271→        removeStyles();
272→      }
273→    }
274→
275→    if (changes.geminiChatWidth) {
276→      const newWidth = changes.geminiChatWidth.newValue;
277→      if (typeof newWidth === 'number') {
278→        const normalized = normalizePercent(newWidth, DEFAULT_PERCENT);
279→        currentWidthPercent = normalized;
280→        if (enabled) {
281→          applyWidth(currentWidthPercent);
282→        }
283→
284→        if (normalized !== newWidth) {
285→          try {
286→            chrome.storage?.sync?.set({ geminiChatWidth: normalized });
287→          } catch (e) {
288→            console.warn('[Gemini Voyager] Failed to migrate chat width to % on change:', e);
289→          }
290→        }
291→      }
292→    }
293→  };
294→
295→  chrome.storage?.onChanged?.addListener(storageChangeHandler);
296→
297→  // Re-apply styles when DOM changes (for dynamic content)
298→  // Use debouncing and cache the width to avoid storage reads
299→  let debounceTimer: number | null = null;
300→  const observer = new MutationObserver(() => {
301→    if (debounceTimer !== null) {
302→      clearTimeout(debounceTimer);
303→    }
304→    debounceTimer = window.setTimeout(() => {
305→      if (enabled) {
306→        applyWidth(currentWidthPercent);
307→      }
308→      debounceTimer = null;
309→    }, 200);
310→  });
311→
312→  // Observe the main conversation area for changes
313→  const main = document.querySelector('main');
314→  if (main) {
315→    observer.observe(main, {
316→      childList: true,
317→      subtree: true,
318→    });
319→  }
320→
321→  // Clean up on unload to prevent memory leaks
322→  window.addEventListener(
323→    'beforeunload',
324→    () => {
325→      observer.disconnect();
326→      removeStyles();
327→      // Remove storage listener
328→      try {
329→        chrome.storage?.onChanged?.removeListener(storageChangeHandler);
330→      } catch (e) {
331→        console.error('[Gemini Voyager] Failed to remove storage listener on unload:', e);
332→      }
333→    },
334→    { once: true },
335→  );
336→}
