 1→import { useEffect, useRef, useState } from 'react';
 2→
 3→interface UseWidthAdjusterOptions {
 4→  storageKey: string;
 5→  defaultValue: number;
 6→  onApply: (value: number) => void;
 7→  /**
 8→   * Optional normalization hook (e.g., migrate legacy px to %)
 9→   */
10→  normalize?: (value: number) => number;
11→}
12→
13→/**
14→ * Custom hook for managing width adjustment with debounced storage writes
15→ * Follows DRY principle by extracting common width adjustment logic
16→ */
17→export function useWidthAdjuster({
18→  storageKey,
19→  defaultValue,
20→  onApply,
21→  normalize,
22→}: UseWidthAdjusterOptions) {
23→  const initial = normalize ? normalize(defaultValue) : defaultValue;
24→  const [width, setWidth] = useState<number>(initial);
25→  const pendingWidth = useRef<number | null>(null);
26→  const hydrated = useRef(false);
27→  const isInteracting = useRef(false);
28→
29→  // Load initial width from storage
30→  useEffect(() => {
31→    try {
32→      chrome.storage?.sync?.get({ [storageKey]: defaultValue }, (res) => {
33→        const storedWidth = res?.[storageKey];
34→        if (typeof storedWidth === 'number') {
35→          const normalized = normalize ? normalize(storedWidth) : storedWidth;
36→          if (Number.isFinite(normalized)) {
37→            // Avoid overriding user drag in progress
38→            if (!isInteracting.current) {
39→              setWidth(normalized);
40→            }
41→          }
42→        }
43→        hydrated.current = true;
44→      });
45→    } catch {}
46→  }, [storageKey, defaultValue, normalize]);
47→
48→  // Cleanup and save pending changes on unmount
49→  useEffect(() => {
50→    return () => {
51→      if (pendingWidth.current !== null) {
52→        onApply(pendingWidth.current);
53→      }
54→    };
55→  }, [onApply]);
56→
57→  const handleChange = (newWidth: number) => {
58→    isInteracting.current = true;
59→    setWidth(newWidth);
60→    pendingWidth.current = newWidth;
61→  };
62→
63→  const handleChangeComplete = () => {
64→    // Save once when user releases the slider
65→    if (pendingWidth.current !== null) {
66→      onApply(pendingWidth.current);
67→      pendingWidth.current = null;
68→    }
69→    // Allow future external sync after interaction ends
70→    isInteracting.current = false;
71→  };
72→
73→  return {
74→    width,
75→    handleChange,
76→    handleChangeComplete,
77→  };
78→}
