 73→export function isElementVisible(element: Element | null, win: Window = window): element is HTMLElement {
 74→  if (!(element instanceof HTMLElement)) return false;
 75→
 76→  let current: HTMLElement | null = element;
 77→  while (current) {
 78→    if (current.hidden || current.getAttribute('aria-hidden') === 'true') {
 79→      return false;
 80→    }
 81→
 82→    const style = win.getComputedStyle(current);
 83→    if (
 84→      style.display === 'none' ||
 85→      style.visibility === 'hidden' ||
 86→      style.visibility === 'collapse' ||
 87→      style.opacity === '0'
 88→    ) {
 89→      return false;
 90→    }
 91→
 92→    current = current.parentElement;
 93→  }
 94→
 95→  return true;
 96→}
