 98→export function hasVisibleStopIndicator(doc: Document = document, win: Window = window): boolean {
 99→  for (const selector of STOP_INDICATOR_SELECTORS) {
100→    const indicators = Array.from(doc.querySelectorAll(selector));
101→    if (indicators.some((indicator) => isElementVisible(indicator, win))) {
102→      return true;
103→    }
104→  }
105→
106→  return false;
