109→function resolveAssistantTurnRoot(element: HTMLElement): HTMLElement {
110→  const selector = ASSISTANT_TURN_ROOT_SELECTORS.join(', ');
111→  return (element.closest(selector) as HTMLElement | null) ?? element;
