114→export function getLatestAssistantTurn(
115→  doc: Document = document,
116→  win: Window = window,
117→): HTMLElement | null {
118→  const roots: HTMLElement[] = [];
119→  const seen = new Set<HTMLElement>();
120→
121→  for (const node of Array.from(doc.querySelectorAll<HTMLElement>(combineSelectors(getAssistantTurnSelectors())))) {
122→    const root = resolveAssistantTurnRoot(node);
123→    if (seen.has(root) || !isElementVisible(root, win)) {
124→      continue;
125→    }
126→    seen.add(root);
127→    roots.push(root);
128→  }
129→
130→  return roots.at(-1) ?? null;
131→}
