133→export function extractAssistantTurnText(turn: HTMLElement): string {
134→  const clone = turn.cloneNode(true) as HTMLElement;
135→
136→  for (const selector of REMOVABLE_CONTENT_SELECTORS) {
137→    clone.querySelectorAll(selector).forEach((node) => node.remove());
138→  }
139→
140→  return clone.textContent?.replace(/\s+/g, ' ').trim() ?? '';
141→}
