143→export function hasMeaningfulAssistantContent(turn: HTMLElement): boolean {
144→  if (extractAssistantTurnText(turn).length > 0) {
145→    return true;
146→  }
147→
148→  return turn.querySelector(CONTENTFUL_CHILD_SELECTORS.join(', ')) !== null;
149→}
