151→export function buildAssistantTurnSignature(
152→  turn: HTMLElement,
153→  doc: Document = document,
154→): string {
155→  const text = extractAssistantTurnText(turn);
156→  const contentfulChildCount = turn.querySelectorAll(CONTENTFUL_CHILD_SELECTORS.join(', ')).length;
157→  const pathname = doc.location?.pathname ?? '';
158→  const assistantTurns = Array.from(
159→    new Set(
160→      Array.from(doc.querySelectorAll<HTMLElement>(combineSelectors(getAssistantTurnSelectors()))).map(
161→        resolveAssistantTurnRoot,
162→      ),
163→    ),
164→  );
165→  const assistantTurnIndex = assistantTurns.indexOf(resolveAssistantTurnRoot(turn));
166→
167→  return `${pathname}::${assistantTurnIndex}::${contentfulChildCount}::${text.slice(-200)}`;
168→}
