174→function playReminderTone(win: Window): void {
175→  const AudioContextCtor = getAudioContextConstructor(win);
176→  if (!AudioContextCtor) return;
177→
178→  const audioContext = new AudioContextCtor();
179→  const gain = audioContext.createGain();
180→  gain.gain.value = 0.0001;
181→  gain.connect(audioContext.destination);
182→
183→  const schedule = () => {
184→    const now = audioContext.currentTime;
185→    const oscillatorA = audioContext.createOscillator();
186→    const oscillatorB = audioContext.createOscillator();
187→
188→    oscillatorA.type = 'sine';
189→    oscillatorA.frequency.setValueAtTime(880, now);
190→    oscillatorB.type = 'sine';
191→    oscillatorB.frequency.setValueAtTime(1174, now + 0.16);
192→
193→    oscillatorA.connect(gain);
194→    oscillatorB.connect(gain);
195→
196→    gain.gain.setValueAtTime(0.0001, now);
197→    gain.gain.exponentialRampToValueAtTime(0.06, now + 0.02);
198→    gain.gain.exponentialRampToValueAtTime(0.03, now + 0.16);
199→    gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.42);
200→
201→    oscillatorA.start(now);
202→    oscillatorA.stop(now + 0.18);
203→    oscillatorB.start(now + 0.16);
204→    oscillatorB.stop(now + 0.42);
205→
206→    win.setTimeout(() => {
207→      void audioContext.close().catch(() => undefined);
208→    }, 700);
209→  };
210→
211→  void audioContext.resume().then(schedule).catch(() => {
212→    void audioContext.close().catch(() => undefined);
213→  });
214→}
