249→    }
250→  };
251→
252→  private readonly handleBodyMutation = (): void => {
253→    this.scheduleEvaluation();
254→  };
255→
256→  private readonly handleStorageChange = (
257→    changes: Record<string, chrome.storage.StorageChange>,
258→    areaName: string,
259→  ): void => {
260→    if (areaName !== 'sync' || !(StorageKeys.GV_RESPONSE_FINISH_REMINDER in changes)) {
261→      return;
262→    }
263→
264→    this.setEnabled(changes[StorageKeys.GV_RESPONSE_FINISH_REMINDER].newValue === true);
265→  };
266→
267→  private readonly handleStopClick = (event: Event): void => {
268→    if (!(event.target instanceof Element)) return;
269→
270→    if (event.target.closest(this.stopIndicatorSelector)) {
271→      this.userStoppedGeneration = true;
272→      this.clearCompletionTimer();
273→    }
274→  };
275→
276→  async init(): Promise<() => void> {
277→    try {
278→      const result = await chrome.storage?.sync?.get({
279→        [StorageKeys.GV_RESPONSE_FINISH_REMINDER]: false,
280→      });
281→      this.setEnabled(result?.[StorageKeys.GV_RESPONSE_FINISH_REMINDER] === true);
282→    } catch (error) {
283→      reminderLogger.warn('Failed to read reminder setting, defaulting to disabled', { error });
284→      this.setEnabled(false);
285→    }
286→
287→    this.doc.addEventListener('click', this.handleStopClick, true);
288→    this.doc.addEventListener('visibilitychange', this.handleAttentionStateChange);
289→    this.win.addEventListener('focus', this.handleAttentionStateChange);
290→    chrome.storage?.onChanged?.addListener(this.handleStorageChange);
291→
292→    return () => {
293→      this.destroy();
294→    };
295→  }
296→
297→  destroy(): void {
298→    this.enabled = false;
299→    this.stopObserver();
300→    this.resetState();
301→    this.stopTitleFlash();
302→    this.doc.removeEventListener('click', this.handleStopClick, true);
303→    this.doc.removeEventListener('visibilitychange', this.handleAttentionStateChange);
304→    this.win.removeEventListener('focus', this.handleAttentionStateChange);
305→    chrome.storage?.onChanged?.removeListener(this.handleStorageChange);
