307→
308→  private setEnabled(enabled: boolean): void {
309→    if (this.enabled === enabled) {
310→      return;
311→    }
312→
313→    this.enabled = enabled;
314→
315→    if (enabled) {
316→      this.startObserver();
317→      this.scheduleEvaluation();
318→      reminderLogger.debug('Response finish reminder enabled');
319→      return;
320→    }
321→
322→    this.stopObserver();
323→    this.resetState();
324→    this.stopTitleFlash();
