346→  }
347→
348→  private resetState(): void {
349→    this.activeAssistantTurn = null;
350→    this.conversationPath = this.doc.location.pathname;
351→    this.currentGenerationId = 0;
352→    this.generationActive = false;
353→    this.lastCompletedSignature = null;
354→    this.pendingCompletionGenerationId = null;
355→    this.userStoppedGeneration = false;
