357→
358→  private clearEvaluationTimer(): void {
359→    if (this.evaluationTimer !== null) {
360→      this.win.clearTimeout(this.evaluationTimer);
361→      this.evaluationTimer = null;
362→    }
363→  }
364→
365→  private clearCompletionTimer(): void {
366→    if (this.completionTimer !== null) {
367→      this.win.clearTimeout(this.completionTimer);
368→      this.completionTimer = null;
369→    }
370→    this.pendingCompletionGenerationId = null;
