372→
373→  private scheduleEvaluation(): void {
374→    if (!this.enabled || !this.doc.body) {
375→      return;
376→    }
377→
378→    this.clearEvaluationTimer();
379→    this.evaluationTimer = this.win.setTimeout(() => {
380→      this.evaluationTimer = null;
381→      this.evaluateState();
382→    }, OBSERVER_DEBOUNCE_MS);
383→  }
384→
385→  private evaluateState(): void {
386→    const nextPath = this.doc.location.pathname;
387→    if (nextPath !== this.conversationPath) {
388→      this.conversationPath = nextPath;
389→      this.activeAssistantTurn = null;
390→      this.generationActive = false;
391→      this.clearCompletionTimer();
392→      this.stopTitleFlash();
393→    }
394→
395→    const generatingNow = hasVisibleStopIndicator(this.doc, this.win);
396→    const latestAssistantTurn = getLatestAssistantTurn(this.doc, this.win);
397→
398→    if (latestAssistantTurn) {
399→      this.activeAssistantTurn = latestAssistantTurn;
400→    }
401→
402→    if (generatingNow) {
403→      this.clearCompletionTimer();
404→
405→      if (!this.generationActive) {
406→        this.generationActive = true;
407→        this.currentGenerationId += 1;
408→        this.userStoppedGeneration = false;
409→        reminderLogger.debug('Detected Gemini response generation start', {
410→          path: this.conversationPath,
411→        });
412→      }
413→
414→      return;
415→    }
416→
417→    if (this.pendingCompletionGenerationId !== null) {
418→      this.scheduleCompletionCheck(this.pendingCompletionGenerationId);
419→      return;
420→    }
421→
422→    if (!this.generationActive) {
423→      return;
424→    }
425→
426→    this.generationActive = false;
427→
428→    if (this.userStoppedGeneration) {
429→      this.userStoppedGeneration = false;
430→      reminderLogger.debug('Suppressed reminder after manual stop');
431→      return;
432→    }
433→
434→    this.scheduleCompletionCheck(this.currentGenerationId);
435→  }
436→
437→  private scheduleCompletionCheck(generationId: number): void {
438→    this.clearCompletionTimer();
439→    this.pendingCompletionGenerationId = generationId;
440→
441→    this.completionTimer = this.win.setTimeout(() => {
442→      this.completionTimer = null;
443→      this.pendingCompletionGenerationId = null;
444→      this.confirmCompletion(generationId);
445→    }, COMPLETION_SETTLE_MS);
446→  }
447→
448→  private confirmCompletion(generationId: number): void {
449→    if (!this.enabled || generationId !== this.currentGenerationId) {
450→      return;
451→    }
452→
453→    if (hasVisibleStopIndicator(this.doc, this.win)) {
454→      this.generationActive = true;
455→      return;
456→    }
457→
458→    const turn = this.resolveAssistantTurn();
459→    if (!turn || !hasMeaningfulAssistantContent(turn)) {
460→      return;
461→    }
462→
463→    const signature = buildAssistantTurnSignature(turn, this.doc);
464→    if (signature === this.lastCompletedSignature) {
465→      return;
466→    }
467→
468→    this.lastCompletedSignature = signature;
469→
470→    if (!isUserAway(this.doc)) {
471→      return;
472→    }
473→
474→    reminderLogger.debug('Triggering response finish reminder', {
475→      path: this.conversationPath,
476→    });
477→
478→    if (this.onReminder) {
479→      this.onReminder();
480→      return;
481→    }
482→
483→    playReminderTone(this.win);
484→    this.startTitleFlash();
485→  }
486→
487→  private resolveAssistantTurn(): HTMLElement | null {
488→    if (this.activeAssistantTurn && this.activeAssistantTurn.isConnected) {
489→      return resolveAssistantTurnRoot(this.activeAssistantTurn);
490→    }
491→
492→    this.activeAssistantTurn = getLatestAssistantTurn(this.doc, this.win);
493→    return this.activeAssistantTurn;
494→  }
