496→  private startTitleFlash(): void {
497→    this.stopTitleFlash();
498→
499→    this.flashAlertTitle = getTranslationSync('responseFinishReminderTitleFlash');
500→    this.flashBaseTitle = this.doc.title;
501→    this.flashShowingAlert = false;
502→
503→    const tick = () => {
504→      if (!isUserAway(this.doc)) {
505→        this.stopTitleFlash();
506→        return;
507→      }
508→
509→      if (!this.flashShowingAlert && this.doc.title !== this.flashAlertTitle) {
510→        this.flashBaseTitle = this.doc.title;
511→      }
512→
513→      this.doc.title = this.flashShowingAlert ? this.flashBaseTitle : this.flashAlertTitle;
514→      this.flashShowingAlert = !this.flashShowingAlert;
515→    };
516→
517→    tick();
518→
519→    this.flashIntervalId = this.win.setInterval(tick, TITLE_FLASH_INTERVAL_MS);
520→    this.flashTimeoutId = this.win.setTimeout(() => {
521→      this.stopTitleFlash();
522→    }, TITLE_FLASH_DURATION_MS);
523→  }
524→
525→  private stopTitleFlash(): void {
526→    if (this.flashIntervalId !== null) {
527→      this.win.clearInterval(this.flashIntervalId);
528→      this.flashIntervalId = null;
529→    }
530→
531→    if (this.flashTimeoutId !== null) {
532→      this.win.clearTimeout(this.flashTimeoutId);
533→      this.flashTimeoutId = null;
534→    }
535→
536→    if (
537→      this.flashAlertTitle &&
538→      (this.flashShowingAlert || this.doc.title === this.flashAlertTitle) &&
539→      this.flashBaseTitle
540→    ) {
541→      this.doc.title = this.flashBaseTitle;
542→    }
543→
544→    this.flashAlertTitle = '';
545→    this.flashBaseTitle = '';
546→    this.flashShowingAlert = false;
547→  }
548→}
